<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0d0d0d;
    color: #e0e0e0;
    font-family: 'Courier New', monospace;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 20px;
  }
  h1 {
    font-size: 2rem;
    color: #4ade80;
    letter-spacing: 4px;
    text-transform: uppercase;
  }
  #score-container {
    font-size: 1.2rem;
    color: #a0a0a0;
  }
  #score {
    color: #4ade80;
    font-weight: bold;
    font-size: 1.5rem;
  }
  #snake {
    border: 2px solid #2a2a2a;
    background: #111;
    display: block;
    box-shadow: 0 0 30px rgba(74, 222, 128, 0.1);
  }
  #controls {
    display: flex;
    gap: 12px;
  }
  button {
    padding: 10px 24px;
    font-size: 1rem;
    font-family: 'Courier New', monospace;
    border: 2px solid #333;
    background: #1a1a1a;
    color: #e0e0e0;
    cursor: pointer;
    border-radius: 4px;
    transition: all 0.15s;
    letter-spacing: 1px;
  }
  button:hover {
    border-color: #4ade80;
    color: #4ade80;
    box-shadow: 0 0 10px rgba(74, 222, 128, 0.2);
  }
  button:active {
    background: #2a2a2a;
  }
  #start { border-color: #4ade80; color: #4ade80; }
  #pause { border-color: #facc15; color: #facc15; }
  #reset { border-color: #f87171; color: #f87171; }
  #message {
    font-size: 1rem;
    color: #666;
    height: 1.5em;
  }
  #message.game-over { color: #f87171; }
</style>
</head>
<body>
<h1>Snake</h1>
<div id="score-container">Score: <span id="score">0</span></div>
<canvas id="snake" width="420" height="420"></canvas>
<div id="controls">
  <button id="start">START</button>
  <button id="pause">PAUSE</button>
  <button id="reset">RESET</button>
</div>
<div id="message">Press START to play</div>

<script>
(function() {
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');
  const messageEl = document.getElementById('message');

  const W = 21, H = 21;
  const CELL = Math.floor(canvas.width / W);

  let state = {};
  let intervalId = null;
  const TICK_MS = 120;

  function initState() {
    const midX = Math.floor(W / 2);
    const midY = Math.floor(H / 2);
    state = {
      snake: [[midX, midY], [midX - 1, midY], [midX - 2, midY]],
      dir: 'right',
      nextDir: 'right',
      foodPos: null,
      scoreVal: 0,
      isAlive: true,
    };
    placeFood();
    updateScore();
  }

  function placeFood() {
    const occupied = new Set(state.snake.map(([x, y]) => `${x},${y}`));
    const free = [];
    for (let x = 0; x < W; x++)
      for (let y = 0; y < H; y++)
        if (!occupied.has(`${x},${y}`)) free.push([x, y]);
    if (free.length === 0) return;
    state.foodPos = free[Math.floor(Math.random() * free.length)];
  }

  function updateScore() {
    scoreEl.textContent = state.scoreVal;
  }

  function step() {
    if (!state.isAlive) return;

    state.dir = state.nextDir;

    const [hx, hy] = state.snake[0];
    let nx = hx, ny = hy;
    if (state.dir === 'up')    ny--;
    if (state.dir === 'down')  ny++;
    if (state.dir === 'left')  nx--;
    if (state.dir === 'right') nx++;

    if (nx < 0 || nx >= W || ny < 0 || ny >= H) {
      endGame();
      return;
    }

    const bodyWithoutTail = state.snake.slice(0, state.snake.length - 1);
    if (bodyWithoutTail.some(([x, y]) => x === nx && y === ny)) {
      endGame();
      return;
    }

    const ate = state.foodPos && nx === state.foodPos[0] && ny === state.foodPos[1];
    state.snake.unshift([nx, ny]);
    if (ate) {
      state.scoreVal++;
      updateScore();
      placeFood();
    } else {
      state.snake.pop();
    }

    draw();
  }

  function endGame() {
    state.isAlive = false;
    stopTicker();
    messageEl.textContent = 'Game Over! Press RESET to play again.';
    messageEl.className = 'game-over';
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.strokeStyle = '#1a1a1a';
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= W; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL, 0);
      ctx.lineTo(x * CELL, H * CELL);
      ctx.stroke();
    }
    for (let y = 0; y <= H; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL);
      ctx.lineTo(W * CELL, y * CELL);
      ctx.stroke();
    }

    if (state.foodPos) {
      const [fx, fy] = state.foodPos;
      const cx = fx * CELL + CELL / 2;
      const cy = fy * CELL + CELL / 2;
      const r = CELL / 2 - 2;
      ctx.fillStyle = '#f87171';
      ctx.shadowColor = '#f87171';
      ctx.shadowBlur = 10;
      ctx.beginPath();
      ctx.arc(cx, cy, r, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;
    }

    state.snake.forEach(([x, y], i) => {
      const alpha = i === 0 ? 1 : Math.max(0.4, 1 - i / state.snake.length * 0.6);
      ctx.fillStyle = i === 0
        ? `rgba(74, 222, 128, ${alpha})`
        : `rgba(34, 197, 94, ${alpha})`;
      ctx.shadowColor = i === 0 ? '#4ade80' : 'transparent';
      ctx.shadowBlur = i === 0 ? 8 : 0;
      const pad = 1;
      ctx.beginPath();
      ctx.roundRect(
        x * CELL + pad, y * CELL + pad,
        CELL - pad * 2, CELL - pad * 2,
        3
      );
      ctx.fill();
    });
    ctx.shadowBlur = 0;

    if (!state.isAlive) {
      ctx.fillStyle = 'rgba(0,0,0,0.55)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#f87171';
      ctx.font = `bold ${Math.floor(CELL * 1.5)}px Courier New`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2);
    }
  }

  function startTicker() {
    if (intervalId) return;
    intervalId = setInterval(step, TICK_MS);
  }

  function stopTicker() {
    if (intervalId) { clearInterval(intervalId); intervalId = null; }
  }

  document.getElementById('start').addEventListener('click', () => {
    if (!state.isAlive) return;
    messageEl.textContent = '';
    messageEl.className = '';
    startTicker();
  });

  document.getElementById('pause').addEventListener('click', () => {
    if (intervalId) {
      stopTicker();
      messageEl.textContent = 'Paused';
      messageEl.className = '';
    } else if (state.isAlive) {
      messageEl.textContent = '';
      startTicker();
    }
  });

  document.getElementById('reset').addEventListener('click', () => {
    stopTicker();
    messageEl.textContent = 'Press START to play';
    messageEl.className = '';
    initState();
    draw();
  });

  const OPPOSITES = { up: 'down', down: 'up', left: 'right', right: 'left' };

  document.addEventListener('keydown', e => {
    const map = {
      ArrowUp: 'up', ArrowDown: 'down',
      ArrowLeft: 'left', ArrowRight: 'right'
    };
    if (map[e.key]) {
      e.preventDefault();
      window.game.setDir(map[e.key]);
    }
  });

  window.game = {
    get w() { return W; },
    get h() { return H; },
    reset() {
      stopTicker();
      messageEl.textContent = 'Press START to play';
      messageEl.className = '';
      initState();
      draw();
    },
    tick() {
      step();
    },
    setDir(d) {
      if (!['up','down','left','right'].includes(d)) return;
      if (OPPOSITES[d] === state.dir) return;
      state.nextDir = d;
    },
    setFood(x, y) {
      state.foodPos = [x, y];
      draw();
    },
    snake() {
      return state.snake.map(([x, y]) => [x, y]);
    },
    food() {
      return state.foodPos ? [state.foodPos[0], state.foodPos[1]] : null;
    },
    alive() {
      return state.isAlive;
    },
    score() {
      return state.scoreVal;
    },
  };

  initState();
  draw();
})();
</script>
</body>
</html>
